window.KJV1769_STRONG_BOOKS["Gal"] = {"osis":"Gal","book":"갈라디아서","verses":{"1:1":{"text":"Paul, an apostle, (not of men, neither by man, but by Jesus Christ, and God the Father, who raised him from the dead;)","words":[["G3972","Paul",0,4],["G0652","an apostle",6,16],["G3756","(not",18,22],["G0575","of",23,25],["G0444","men",26,29],["G3761","neither",31,38],["G1223","by",39,41],["G0444","man",42,45],["G0235","but",47,50],["G1223","by",51,53],["G2424","Jesus",54,59],["G5547","Christ",60,66],["G2532","and",68,71],["G2316","God",72,75],["G3962","the Father",76,86],["G3588","who",88,91],["G1453","raised",92,98],["G0846","him",99,102],["G1537","from",103,107],["G3498","the dead",108,116]]},"1:2":{"text":"And all the brethren which are with me, unto the churches of Galatia:","words":[["G2532","And",0,3],["G3956","all",4,7],["G0080","the brethren",8,20],["G4862","which are with",21,35],["G1698","me",36,38],["G1577","unto the churches",40,57],["G1053","of Galatia",58,68]]},"1:3":{"text":"Grace be to you and peace from God the Father, and from our Lord Jesus Christ,","words":[["G5485","Grace",0,5],["G5213","be to you",6,15],["G2532","and",16,19],["G1515","peace",20,25],["G0575","from",26,30],["G2316","God",31,34],["G3962","the Father",35,45],["G2532","and",47,50],["G2257","from our",51,59],["G2962","Lord",60,64],["G2424","Jesus",65,70],["G5547","Christ",71,77]]},"1:4":{"text":"Who gave himself for our sins, that he might deliver us from this present evil world, according to the will of God and our Father:","words":[["G3588","Who",0,3],["G1325","gave",4,8],["G1438","himself",9,16],["G5228","for",17,20],["G2257","our",21,24],["G0266","sins",25,29],["G3704","that",31,35],["G1807","he might deliver",36,52],["G2248","us",53,55],["G1537","from",56,60],["G1764","this present",61,73],["G4190","evil",74,78],["G0165","world",79,84],["G2596","according",86,95],["G2307","to the will",96,107],["G2316","of God",108,114],["G2532","and",115,118],["G2257","our",119,122],["G3962","Father",123,129]]},"1:5":{"text":"To whom be glory for ever and ever. Amen.","words":[["G3739","To whom",0,7],["G1391","be glory",8,16],["G1519","for",17,20],["G0165","ever",21,25],["G0165","and ever",26,34],["G0281","Amen",36,40]]},"1:6":{"text":"I marvel that ye are so soon removed from him that called you into the grace of Christ unto another gospel:","words":[["G2296","I marvel",0,8],["G3754","that",9,13],["G3346","ye are",14,20],["G3779","so",21,23],["G5030","soon",24,28],["G3346","removed",29,36],["G0575","from",37,41],["G2564","him that called",42,57],["G5209","you",58,61],["G1722","into",62,66],["G5485","the grace",67,76],["G5547","of Christ",77,86],["G1519","unto",87,91],["G2087","another",92,99],["G2098","gospel",100,106]]},"1:7":{"text":"Which is not another; but there be some that trouble you, and would pervert the gospel of Christ.","words":[["G3739","Which",0,5],["G2076","is",6,8],["G3756","not",9,12],["G0243","another",13,20],["G1526","but there be",22,34],["G5100","some",35,39],["G1508","that",40,44],["G5015","trouble",45,52],["G5209","you",53,56],["G2532","and",58,61],["G2309","would",62,67],["G3344","pervert",68,75],["G2098","the gospel",76,86],["G5547","of Christ",87,96]]},"1:8":{"text":"But though we, or an angel from heaven, preach any other gospel unto you than that which we have preached unto you, let him be accursed.","words":[["G0235","But",0,3],["G2532","though",4,10],["G1437","though",4,10],["G2249","we",11,13],["G2228","or",15,17],["G0032","an angel",18,26],["G1537","from",27,31],["G3772","heaven",32,38],["G2097","preach any other gospel",40,63],["G5213","unto you",64,72],["G3844","than",73,77],["G3739","that which",78,88],["G2097","we have preached",89,105],["G5213","unto you",106,114],["G2077","let him be",116,126],["G0331","accursed",127,135]]},"1:9":{"text":"As we said before, so say I now again, If any man preach any other gospel unto you than that ye have received, let him be accursed.","words":[["G5613","As",0,2],["G4280","we said before",3,17],["G2532","so",19,21],["G3004","say I",22,27],["G0737","now",28,31],["G3825","again",32,37],["G1536","If any",39,45],["G2097","man preach",46,56],["G3844","any other",57,66],["G2097","gospel",67,73],["G5209","unto you",74,82],["G3844","than",83,87],["G3739","that",88,92],["G3880","ye have received",93,109],["G2077","let him be",111,121],["G0331","accursed",122,130]]},"1:10":{"text":"For do I now persuade men, or God? or do I seek to please men? for if I yet pleased men, I should not be the servant of Christ.","words":[["G1063","For",0,3],["G3982","do I",4,8],["G0737","now",9,12],["G3982","persuade",13,21],["G0444","men",22,25],["G2228","or",27,29],["G2316","God",30,33],["G2228","or",35,37],["G2212","do I seek",38,47],["G0700","to please",48,57],["G0444","men",58,61],["G1063","for",63,66],["G1487","if",67,69],["G0700","I",70,71],["G2089","yet",72,75],["G0700","pleased",76,83],["G0444","men",84,87],["G0302","I should",89,97],["G3756","not",98,101],["G2252","be",102,104],["G1401","the servant",105,116],["G5547","of Christ",117,126]]},"1:11":{"text":"But I certify you, brethren, that the gospel which was preached of me is not after man.","words":[["G1161","But",0,3],["G1107","I certify",4,13],["G5213","you",14,17],["G0080","brethren",19,27],["G3754","that",29,33],["G2098","the gospel",34,44],["G3588","which",45,50],["G2097","was preached",51,63],["G5259","of",64,66],["G1700","me",67,69],["G2076","is",70,72],["G3756","not",73,76],["G2596","after",77,82],["G0444","man",83,86]]},"1:12":{"text":"For I neither received it of man, neither was I taught it, but by the revelation of Jesus Christ.","words":[["G1063","For",0,3],["G1473","I",4,5],["G3761","neither",6,13],["G3880","received",14,22],["G0846","it",23,25],["G3844","of",26,28],["G0444","man",29,32],["G3777","neither",34,41],["G1321","was I taught",42,54],["G0235","it, but",55,62],["G1223","by",63,65],["G0602","the revelation",66,80],["G2424","of Jesus",81,89],["G5547","Christ",90,96]]},"1:13":{"text":"For ye have heard of my conversation in time past in the Jews' religion, how that beyond measure I persecuted the church of God, and wasted it:","words":[["G1063","For",0,3],["G0191","ye have heard",4,17],["G1699","of my",18,23],["G0391","conversation",24,36],["G4218","in time past",37,49],["G1722","in",50,52],["G2454","the Jews' religion",53,71],["G3754","how that",73,81],["G2596","beyond",82,88],["G5236","measure",89,96],["G1377","I persecuted",97,109],["G1577","the church",110,120],["G2316","of God",121,127],["G2532","and",129,132],["G4199","wasted",133,139],["G0846","it",140,142]]},"1:14":{"text":"And profited in the Jews' religion above many my equals in mine own nation, being more exceedingly zealous of the traditions of my fathers.","words":[["G2532","And",0,3],["G4298","profited",4,12],["G1722","in",13,15],["G2454","the Jews' religion",16,34],["G5228","above",35,40],["G4183","many",41,45],["G4915","my equals",46,55],["G1722","in",56,58],["G3450","mine own",59,67],["G1085","nation",68,74],["G5225","being",76,81],["G4056","more exceedingly",82,98],["G2207","zealous",99,106],["G3862","of the traditions",107,124],["G3450","of my",125,130],["G3967","fathers",131,138]]},"1:15":{"text":"But when it pleased God, who separated me from my mother's womb, and called me by his grace,","words":[["G1161","But",0,3],["G3753","when",4,8],["G2106","it pleased",9,19],["G2316","God",20,23],["G3588","who",25,28],["G0873","separated",29,38],["G3165","me",39,41],["G1537","from",42,46],["G3450","my",47,49],["G3384","mother's",50,58],["G2836","womb",59,63],["G2532","and",65,68],["G2564","called",69,75],["G1223","me by",76,81],["G0846","his",82,85],["G5485","grace",86,91]]},"1:16":{"text":"To reveal his Son in me, that I might preach him among the heathen; immediately I conferred not with flesh and blood:","words":[["G0601","To reveal",0,9],["G0846","his",10,13],["G5207","Son",14,17],["G1722","in",18,20],["G1698","me",21,23],["G2443","that",25,29],["G2097","I might preach",30,44],["G0846","him",45,48],["G1722","among",49,54],["G1484","the heathen",55,66],["G2112","immediately",68,79],["G4323","I conferred",80,91],["G3756","not",92,95],["G4561","with flesh",96,106],["G2532","and",107,110],["G0129","blood",111,116]]},"1:17":{"text":"Neither went I up to Jerusalem to them which were apostles before me; but I went into Arabia, and returned again unto Damascus.","words":[["G3761","Neither",0,7],["G0424","went I up",8,17],["G1519","to",18,20],["G2414","Jerusalem",21,30],["G4314","to",31,33],["G0652","them which were apostles",34,58],["G4253","before",59,65],["G1700","me",66,68],["G0235","but",70,73],["G0565","I went",74,80],["G1519","into",81,85],["G0688","Arabia",86,92],["G2532","and",94,97],["G5290","returned",98,106],["G3825","again",107,112],["G1519","unto",113,117],["G1154","Damascus",118,126]]},"1:18":{"text":"Then after three years I went up to Jerusalem to see Peter, and abode with him fifteen days.","words":[["G1899","Then",0,4],["G3326","after",5,10],["G5140","three",11,16],["G2094","years",17,22],["G0424","I went up",23,32],["G1519","to",33,35],["G2414","Jerusalem",36,45],["G2477","to see",46,52],["G4074","Peter",53,58],["G2532","and",60,63],["G1961","abode",64,69],["G4314","with",70,74],["G0846","him",75,78],["G1178","fifteen",79,86],["G2250","days",87,91]]},"1:19":{"text":"But other of the apostles saw I none, save James the Lord's brother.","words":[["G1161","But",0,3],["G2087","other",4,9],["G0652","of the apostles",10,25],["G1492","saw I",26,31],["G3756","none",32,36],["G1508","save",38,42],["G2385","James",43,48],["G2962","the Lord's",49,59],["G0080","brother",60,67]]},"1:20":{"text":"Now the things which I write unto you, behold, before God, I lie not.","words":[["G1161","Now",0,3],["G3739","the things which",4,20],["G1125","I write",21,28],["G5213","unto you",29,37],["G2400","behold",39,45],["G1799","before",47,53],["G2316","God",54,57],["G3754","",-1,-1],["G5574","I lie",59,64],["G3756","not",65,68]]},"1:21":{"text":"Afterwards I came into the regions of Syria and Cilicia;","words":[["G1899","Afterwards",0,10],["G2064","I came",11,17],["G1519","into",18,22],["G2824","the regions",23,34],["G4947","of Syria",35,43],["G2532","and",44,47],["G2791","Cilicia",48,55]]},"1:22":{"text":"And was unknown by face unto the churches of Judaea which were in Christ:","words":[["G1161","And",0,3],["G2252","was",4,7],["G0050","unknown",8,15],["G4383","by face",16,23],["G1577","unto the churches",24,41],["G2449","of Judaea",42,51],["G3588","which",52,57],["G1722","were in",58,65],["G5547","Christ",66,72]]},"1:23":{"text":"But they had heard only, That he which persecuted us in times past now preacheth the faith which once he destroyed.","words":[["G1161","But",0,3],["G2258","they had",4,12],["G0191","heard",13,18],["G3440","only",19,23],["G3754","That",25,29],["G1377","he which persecuted",30,49],["G2248","us",50,52],["G4218","in times past",53,66],["G3568","now",67,70],["G2097","preacheth",71,80],["G4102","the faith",81,90],["G3739","which",91,96],["G4218","once",97,101],["G4199","he destroyed",102,114]]},"1:24":{"text":"And they glorified God in me.","words":[["G2532","And",0,3],["G1392","they glorified",4,18],["G2316","God",19,22],["G1722","in",23,25],["G1698","me",26,28]]},"2:1":{"text":"Then fourteen years after I went up again to Jerusalem with Barnabas, and took Titus with me also.","words":[["G1899","Then",0,4],["G1180","fourteen",5,13],["G2094","years",14,19],["G1223","after",20,25],["G0305","I went up",26,35],["G3825","again",36,41],["G1519","to",42,44],["G2414","Jerusalem",45,54],["G3326","with",55,59],["G0921","Barnabas",60,68],["G4838","and took",70,78],["G5103","Titus",79,84],["G4838","with me",85,92],["G2532","also",93,97]]},"2:2":{"text":"And I went up by revelation, and communicated unto them that gospel which I preach among the Gentiles, but privately to them which were of reputation, lest by any means I should run, or had run, in vain.","words":[["G1161","And",0,3],["G0305","I went up",4,13],["G2596","by",14,16],["G0602","revelation",17,27],["G2532","and",29,32],["G0394","communicated",33,45],["G0846","unto them",46,55],["G2098","that gospel",56,67],["G3739","which",68,73],["G2784","I preach",74,82],["G1722","among",83,88],["G1484","the Gentiles",89,101],["G1161","but",103,106],["G2596","privately",107,116],["G2398","privately",107,116],["G1380","to them which were of reputation",117,149],["G3381","lest by any means",151,168],["G4458","lest by any means",151,168],["G5143","I should run",169,181],["G2228","or",183,185],["G5143","had run",186,193],["G1519","in",195,197],["G2756","vain",198,202]]},"2:3":{"text":"But neither Titus, who was with me, being a Greek, was compelled to be circumcised:","words":[["G0235","But",0,3],["G3761","neither",4,11],["G5103","Titus",12,17],["G3588","who",19,22],["G4862","was with",23,31],["G1698","me",32,34],["G5607","being",36,41],["G1672","a Greek",42,49],["G0315","was compelled",51,64],["G4059","to be circumcised",65,82]]},"2:4":{"text":"And that because of false brethren unawares brought in, who came in privily to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage:","words":[["G1161","And",0,3],["G1223","that because of",4,19],["G5569","false brethren",20,34],["G3920","unawares brought in",35,54],["G3748","who",56,59],["G3922","came in privily",60,75],["G2684","to spy out",76,86],["G2257","our",87,90],["G1657","liberty",91,98],["G3739","which",99,104],["G2192","we have",105,112],["G1722","in",113,115],["G5547","Christ",116,122],["G2424","Jesus",123,128],["G2443","that",130,134],["G2615","they might bring",135,151],["G2248","us",152,154],["G2615","into bondage",155,167]]},"2:5":{"text":"To whom we gave place by subjection, no, not for an hour; that the truth of the gospel might continue with you.","words":[["G3739","To whom",0,7],["G1502","we gave place",8,21],["G5292","by subjection",22,35],["G3761","no, not",37,44],["G4314","for",45,48],["G5610","an hour",49,56],["G2443","that",58,62],["G0225","the truth",63,72],["G2098","of the gospel",73,86],["G1265","might continue",87,101],["G4314","with",102,106],["G5209","you",107,110]]},"2:6":{"text":"But of these who seemed to be somewhat, (whatsoever they were, it maketh no matter to me: God accepteth no man's person:) for they who seemed to be somewhat in conference added nothing to me:","words":[["G1161","But",0,3],["G0575","of",4,6],["G1380","these who seemed",7,23],["G1511","to be",24,29],["G5100","somewhat",30,38],["G3697","(whatsoever",40,51],["G4218","(whatsoever",40,51],["G2258","they were",52,61],["G1308","it maketh",63,72],["G3762","no",73,75],["G1308","matter",76,82],["G3427","to me",83,88],["G2316","God",90,93],["G2983","accepteth",94,103],["G3756","no",104,106],["G0444","man's",107,112],["G4383","person",113,119],["G1063",") for",120,125],["G1380","they who seemed",126,141],["G4323","to be somewhat in conference added",142,176],["G3762","nothing",177,184],["G1698","to me",185,190]]},"2:7":{"text":"But contrariwise, when they saw that the gospel of the uncircumcision was committed unto me, as the gospel of the circumcision was unto Peter;","words":[["G0235","But",0,3],["G5121","contrariwise",4,16],["G1492","when they saw",18,31],["G3754","that",32,36],["G2098","the gospel",37,47],["G0203","of the uncircumcision",48,69],["G4100","was committed unto me",70,91],["G2531","as",93,95],["G4061","the gospel of the circumcision",96,126],["G4074","was unto Peter",127,141]]},"2:8":{"text":"(For he that wrought effectually in Peter to the apostleship of the circumcision, the same was mighty in me toward the Gentiles:)","words":[["G1063","(For",0,4],["G1754","he that wrought effectually",5,32],["G4074","in Peter",33,41],["G1519","to",42,44],["G0651","the apostleship",45,60],["G4061","of the circumcision",61,80],["G2532","the same",82,90],["G1754","was mighty",91,101],["G1698","in me",102,107],["G1519","toward",108,114],["G1484","the Gentiles",115,127]]},"2:9":{"text":"And when James, Cephas, and John, who seemed to be pillars, perceived the grace that was given unto me, they gave to me and Barnabas the right hands of fellowship; that we should go unto the heathen, and they unto the circumcision.","words":[["G2532","And",0,3],["G2385","when James",4,14],["G2532","",-1,-1],["G2786","Cephas",16,22],["G2532","and",24,27],["G2491","John",28,32],["G3588","who",34,37],["G1380","seemed",38,44],["G1511","to be",45,50],["G4769","pillars",51,58],["G1097","perceived",60,69],["G5485","the grace",70,79],["G1325","that was given",80,94],["G3427","unto me",95,102],["G1325","they gave",104,113],["G1698","to me",114,119],["G2532","and",120,123],["G0921","Barnabas",124,132],["G1188","the right hands",133,148],["G2842","of fellowship",149,162],["G2443","that",164,168],["G2249","we",169,171],["G1519","should go unto",172,186],["G1484","the heathen",187,198],["G1161","and",200,203],["G0846","they",204,208],["G1519","unto",209,213],["G4061","the circumcision",214,230]]},"2:10":{"text":"Only they would that we should remember the poor; the same which I also was forward to do.","words":[["G3440","Only",0,4],["G2443","they would that",5,20],["G3421","we should remember",21,39],["G4434","the poor",40,48],["G0846","the same",50,58],["G5124","the same",50,58],["G3739","which",59,64],["G4704","I",65,66],["G2532","also",67,71],["G4704","was forward",72,83],["G4160","to do",84,89]]},"2:11":{"text":"But when Peter was come to Antioch, I withstood him to the face, because he was to be blamed.","words":[["G1161","But",0,3],["G3753","when",4,8],["G4074","Peter",9,14],["G2064","was come",15,23],["G1519","to",24,26],["G0490","Antioch",27,34],["G0436","I withstood",36,47],["G0846","him",48,51],["G2596","to",52,54],["G4383","the face",55,63],["G3754","because",65,72],["G2258","he was",73,79],["G2607","to be blamed",80,92]]},"2:12":{"text":"For before that certain came from James, he did eat with the Gentiles: but when they were come, he withdrew and separated himself, fearing them which were of the circumcision.","words":[["G1063","For",0,3],["G4253","before",4,10],["G5100","that certain",11,23],["G2064","came",24,28],["G0575","from",29,33],["G2385","James",34,39],["G4906","he did eat",41,51],["G3326","with",52,56],["G1484","the Gentiles",57,69],["G1161","but",71,74],["G3753","when",75,79],["G2064","they were come",80,94],["G5288","he withdrew",96,107],["G2532","and",108,111],["G0873","separated",112,121],["G1438","himself",122,129],["G5399","fearing",131,138],["G1537","them which were of",139,157],["G4061","the circumcision",158,174]]},"2:13":{"text":"And the other Jews dissembled likewise with him; insomuch that Barnabas also was carried away with their dissimulation.","words":[["G2532","And",0,3],["G3062","the other",4,13],["G2453","Jews",14,18],["G4942","dissembled",19,29],["G2532","likewise",30,38],["G0846","with him",39,47],["G5620","insomuch",49,57],["G0921","that Barnabas",58,71],["G2532","also",72,76],["G4879","was carried away",77,93],["G0846","with their",94,104],["G5272","dissimulation",105,118]]},"2:14":{"text":"But when I saw that they walked not uprightly according to the truth of the gospel, I said unto Peter before them all, If thou, being a Jew, livest after the manner of Gentiles, and not as do the Jews, why compellest thou the Gentiles to live as do the Jews?","words":[["G0235","But",0,3],["G3753","when",4,8],["G1492","I saw",9,14],["G3754","that",15,19],["G3716","they walked",20,31],["G3756","not",32,35],["G3716","uprightly",36,45],["G4314","according to",46,58],["G0225","the truth",59,68],["G2098","of the gospel",69,82],["G2036","I said",84,90],["G4074","unto Peter",91,101],["G1715","before",102,108],["G3956","them all",109,117],["G1487","If",119,121],["G4771","thou",122,126],["G5225","being",128,133],["G2453","a Jew",134,139],["G2198","livest",141,147],["G1483","after the manner of Gentiles",148,176],["G2532","and",178,181],["G3756","not",182,185],["G2452","as do the Jews",186,200],["G5101","why",202,205],["G0315","compellest thou",206,221],["G1484","the Gentiles",222,234],["G2450","to live as do the Jews",235,257]]},"2:15":{"text":"We who are Jews by nature, and not sinners of the Gentiles,","words":[["G2249","We",0,2],["G2453","who are Jews",3,15],["G5449","by nature",16,25],["G2532","and",27,30],["G3756","not",31,34],["G0268","sinners",35,42],["G1537","of",43,45],["G1484","the Gentiles",46,58]]},"2:16":{"text":"Knowing that a man is not justified by the works of the law, but by the faith of Jesus Christ, even we have believed in Jesus Christ, that we might be justified by the faith of Christ, and not by the works of the law: for by the works of the law shall no flesh be justified.","words":[["G1492","Knowing",0,7],["G3754","that",8,12],["G0444","a man",13,18],["G1344","is",19,21],["G3756","not",22,25],["G1344","justified",26,35],["G1537","by",36,38],["G2041","the works",39,48],["G3551","of the law",49,59],["G3362","but",61,64],["G1223","by",65,67],["G4102","the faith",68,77],["G2424","of Jesus",78,86],["G5547","Christ",87,93],["G2532","even",95,99],["G2249","we",100,102],["G4100","have believed",103,116],["G1519","in",117,119],["G2424","Jesus",120,125],["G5547","Christ",126,132],["G2443","that",134,138],["G1344","we might be justified",139,160],["G1537","by",161,163],["G4102","the faith",164,173],["G5547","of Christ",174,183],["G2532","and",185,188],["G3756","not",189,192],["G1537","by",193,195],["G2041","the works",196,205],["G3551","of the law",206,216],["G1360","for",218,221],["G1537","by",222,224],["G2041","the works",225,234],["G3551","of the law",235,245],["G1344","shall",246,251],["G3756","no",252,254],["G3956","no",252,254],["G4561","flesh",255,260],["G1344","be justified",261,273]]},"2:17":{"text":"But if, while we seek to be justified by Christ, we ourselves also are found sinners, is therefore Christ the minister of sin? God forbid.","words":[["G1161","But",0,3],["G1487","if",4,6],["G2212","while we seek",8,21],["G1344","to be justified",22,37],["G1722","by",38,40],["G5547","Christ",41,47],["G2147","we",49,51],["G0846","ourselves",52,61],["G2532","also",62,66],["G2147","are found",67,76],["G0268","sinners",77,84],["G0687","is therefore",86,98],["G5547","Christ",99,105],["G1249","the minister",106,118],["G0266","of sin",119,125],["G3361","God forbid",127,137],["G1096","God forbid",127,137]]},"2:18":{"text":"For if I build again the things which I destroyed, I make myself a transgressor.","words":[["G1063","For",0,3],["G1487","if",4,6],["G3618","I build",7,14],["G3825","again",15,20],["G5023","the things",21,31],["G3739","which",32,37],["G2647","I destroyed",38,49],["G4921","I make",51,57],["G1683","myself",58,64],["G3848","a transgressor",65,79]]},"2:19":{"text":"For I through the law am dead to the law, that I might live unto God.","words":[["G1063","For",0,3],["G1473","I",4,5],["G1223","through",6,13],["G3551","the law",14,21],["G0599","am dead",22,29],["G3551","to the law",30,40],["G2443","that",42,46],["G2198","I might live",47,59],["G2316","unto God",60,68]]},"2:20":{"text":"I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me.","words":[["G4957","I am crucified",0,14],["G5547","with Christ",15,26],["G1161","nevertheless",28,40],["G2198","I live",41,47],["G3765","yet not",49,56],["G1473","I",57,58],["G1161","but",60,63],["G5547","Christ",64,70],["G2198","liveth",71,77],["G1722","in",78,80],["G1698","me",81,83],["G1161","and",85,88],["G3739","the life which",89,103],["G2198","I",104,105],["G3568","now",106,109],["G2198","live",110,114],["G1722","in",115,117],["G4561","the flesh",118,127],["G2198","I live",128,134],["G1722","by",135,137],["G4102","the faith",138,147],["G5207","of the Son",148,158],["G2316","of God",159,165],["G3588","who",167,170],["G0025","loved",171,176],["G3165","me",177,179],["G2532","and",181,184],["G3860","gave",185,189],["G1438","himself",190,197],["G5228","for",198,201],["G1700","me",202,204]]},"2:21":{"text":"I do not frustrate the grace of God: for if righteousness come by the law, then Christ is dead in vain.","words":[["G0114","I do",0,4],["G3756","not",5,8],["G0114","frustrate",9,18],["G5485","the grace",19,28],["G2316","of God",29,35],["G1063","for",37,40],["G1487","if",41,43],["G1343","righteousness",44,57],["G1223","come by",58,65],["G3551","the law",66,73],["G0686","then",75,79],["G5547","Christ",80,86],["G0599","is dead",87,94],["G1432","in vain",95,102]]},"3:1":{"text":"O foolish Galatians, who hath bewitched you, that ye should not obey the truth, before whose eyes Jesus Christ hath been evidently set forth, crucified among you?","words":[["G5599","O",0,1],["G0453","foolish",2,9],["G1052","Galatians",10,19],["G5101","who",21,24],["G0940","hath bewitched",25,39],["G5209","you",40,43],["G3982","that ye should",45,59],["G3361","not",60,63],["G3982","obey",64,68],["G0225","the truth",69,78],["G2596","before",80,86],["G3739","whose",87,92],["G3788","eyes",93,97],["G2424","Jesus",98,103],["G5547","Christ",104,110],["G4270","hath been evidently set forth",111,140],["G4717","crucified",142,151],["G1722","among",152,157],["G5213","you",158,161]]},"3:2":{"text":"This only would I learn of you, Received ye the Spirit by the works of the law, or by the hearing of faith?","words":[["G5124","This",0,4],["G3440","only",5,9],["G2309","would",10,15],["G3129","I learn",16,23],["G0575","of",24,26],["G5216","you",27,30],["G2983","Received ye",32,43],["G4151","the Spirit",44,54],["G1537","by",55,57],["G2041","the works",58,67],["G3551","of the law",68,78],["G2228","or",80,82],["G1537","by",83,85],["G0189","the hearing",86,97],["G4102","of faith",98,106]]},"3:3":{"text":"Are ye so foolish? having begun in the Spirit, are ye now made perfect by the flesh?","words":[["G2075","Are ye",0,6],["G3779","so",7,9],["G0453","foolish",10,17],["G1728","having begun",19,31],["G4151","in the Spirit",32,45],["G2005","are ye",47,53],["G3568","now",54,57],["G2005","made perfect",58,70],["G4561","by the flesh",71,83]]},"3:4":{"text":"Have ye suffered so many things in vain? if it be yet in vain.","words":[["G3958","Have ye suffered",0,16],["G5118","so many things",17,31],["G1500","in vain",32,39],["G1489","if it be yet",41,53],["G2532","if it be yet",41,53],["G1500","in vain",54,61]]},"3:5":{"text":"He therefore that ministereth to you the Spirit, and worketh miracles among you, doeth he it by the works of the law, or by the hearing of faith?","words":[["G3767","He therefore",0,12],["G2023","that ministereth",13,29],["G5213","to you",30,36],["G4151","the Spirit",37,47],["G2532","and",49,52],["G1754","worketh",53,60],["G1411","miracles",61,69],["G1722","among",70,75],["G5213","you",76,79],["G1537","doeth he it by",81,95],["G2041","the works",96,105],["G3551","of the law",106,116],["G2228","or",118,120],["G1537","by",121,123],["G0189","the hearing",124,135],["G4102","of faith",136,144]]},"3:6":{"text":"Even as Abraham believed God, and it was accounted to him for righteousness.","words":[["G2531","Even as",0,7],["G0011","Abraham",8,15],["G4100","believed",16,24],["G2316","God",25,28],["G2532","and",30,33],["G3049","it was accounted",34,50],["G0846","to him",51,57],["G1519","for",58,61],["G1343","righteousness",62,75]]},"3:7":{"text":"Know ye therefore that they which are of faith, the same are the children of Abraham.","words":[["G1097","Know ye",0,7],["G0686","therefore",8,17],["G3754","that",18,22],["G1537","they which are of",23,40],["G4102","faith",41,46],["G3778","the same",48,56],["G1526","are",57,60],["G5207","the children",61,73],["G0011","of Abraham",74,84]]},"3:8":{"text":"And the scripture, foreseeing that God would justify the heathen through faith, preached before the gospel unto Abraham, saying, In thee shall all nations be blessed.","words":[["G1161","And",0,3],["G1124","the scripture",4,17],["G4275","foreseeing",19,29],["G3754","that",30,34],["G2316","God",35,38],["G1344","would justify",39,52],["G1484","the heathen",53,64],["G1537","through",65,72],["G4102","faith",73,78],["G4283","preached before the gospel",80,106],["G0011","unto Abraham",107,119],["G3754","saying,",121,128],["G1722","In",129,131],["G4671","thee",132,136],["G1757","shall",137,142],["G3956","all",143,146],["G1484","nations",147,154],["G1757","be blessed",155,165]]},"3:9":{"text":"So then they which be of faith are blessed with faithful Abraham.","words":[["G5620","So then",0,7],["G1537","they which be of",8,24],["G4102","faith",25,30],["G2127","are blessed",31,42],["G4862","with",43,47],["G4103","faithful",48,56],["G0011","Abraham",57,64]]},"3:10":{"text":"For as many as are of the works of the law are under the curse: for it is written, Cursed is every one that continueth not in all things which are written in the book of the law to do them.","words":[["G1063","For",0,3],["G3745","as many as",4,14],["G1526","are",15,18],["G1537","of",19,21],["G2041","the works",22,31],["G3551","of the law",32,42],["G1526","are",43,46],["G5259","under",47,52],["G2671","the curse",53,62],["G1063","for",64,67],["G1125","it is written",68,81],["G1944","Cursed",83,89],["G3956","is every one",90,102],["G3739","that",103,107],["G1696","continueth",108,118],["G3756","not",119,122],["G1722","in",123,125],["G3956","all things",126,136],["G3588","which",137,142],["G1125","are written",143,154],["G1722","in",155,157],["G0975","the book",158,166],["G3551","of the law",167,177],["G4160","to do",178,183],["G0846","them",184,188]]},"3:11":{"text":"But that no man is justified by the law in the sight of God, it is evident: for, The just shall live by faith.","words":[["G1161","But",0,3],["G3754","that",4,8],["G3762","no man",9,15],["G1344","is justified",16,28],["G1722","by",29,31],["G3551","the law",32,39],["G3844","in the sight",40,52],["G2316","of God",53,59],["G1212","it is evident",61,74],["G3754","for",76,79],["G1342","The just",81,89],["G2198","shall live",90,100],["G1537","by",101,103],["G4102","faith",104,109]]},"3:12":{"text":"And the law is not of faith: but, The man that doeth them shall live in them.","words":[["G1161","And",0,3],["G3551","the law",4,11],["G2076","is",12,14],["G3756","not",15,18],["G1537","of",19,21],["G4102","faith",22,27],["G0235","but",29,32],["G0444","The man",34,41],["G4160","that doeth",42,52],["G0846","them",53,57],["G2198","shall live",58,68],["G1722","in",69,71],["G0846","them",72,76]]},"3:13":{"text":"Christ hath redeemed us from the curse of the law, being made a curse for us: for it is written, Cursed is every one that hangeth on a tree:","words":[["G5547","Christ",0,6],["G1805","hath redeemed",7,20],["G2248","us",21,23],["G1537","from",24,28],["G2671","the curse",29,38],["G3551","of the law",39,49],["G1096","being made",51,61],["G2671","a curse",62,69],["G5228","for",70,73],["G2257","us",74,76],["G1063","for",78,81],["G1125","it is written",82,95],["G1944","Cursed",97,103],["G3956","is every one",104,116],["G2910","that hangeth",117,129],["G1909","on",130,132],["G3586","a tree",133,139]]},"3:14":{"text":"That the blessing of Abraham might come on the Gentiles through Jesus Christ; that we might receive the promise of the Spirit through faith.","words":[["G2443","That",0,4],["G2129","the blessing",5,17],["G0011","of Abraham",18,28],["G1096","might come",29,39],["G1519","on",40,42],["G1484","the Gentiles",43,55],["G1722","through",56,63],["G2424","Jesus",64,69],["G5547","Christ",70,76],["G2443","that",78,82],["G2983","we might receive",83,99],["G1860","the promise",100,111],["G4151","of the Spirit",112,125],["G1223","through",126,133],["G4102","faith",134,139]]},"3:15":{"text":"Brethren, I speak after the manner of men; Though it be but a man's covenant, yet if it be confirmed, no man disannulleth, or addeth thereto.","words":[["G0080","Brethren",0,8],["G3004","I speak",10,17],["G2596","after the manner of",18,37],["G0444","men",38,41],["G3676","Though it be but",43,59],["G0444","a man's",60,67],["G1242","covenant",68,76],["G2964","yet if it be confirmed",78,100],["G3762","no man",102,108],["G0114","disannulleth",109,121],["G2228","or",123,125],["G1928","addeth thereto",126,140]]},"3:16":{"text":"Now to Abraham and his seed were the promises made. He saith not, And to seeds, as of many; but as of one, And to thy seed, which is Christ.","words":[["G1161","Now",0,3],["G0011","to Abraham",4,14],["G2532","and",15,18],["G0846","his",19,22],["G4690","seed",23,27],["G4483","were",28,32],["G1860","the promises",33,45],["G4483","made",46,50],["G3004","He saith",52,60],["G3756","not",61,64],["G2532","And",66,69],["G4690","to seeds",70,78],["G5613","as",80,82],["G1909","of",83,85],["G4183","many",86,90],["G0235","but",92,95],["G5613","as",96,98],["G1909","of",99,101],["G1520","one",102,105],["G2532","And",107,110],["G4675","to thy",111,117],["G4690","seed",118,122],["G3739","which",124,129],["G2076","is",130,132],["G5547","Christ",133,139]]},"3:17":{"text":"And this I say, that the covenant, that was confirmed before of God in Christ, the law, which was four hundred and thirty years after, cannot disannul, that it should make the promise of none effect.","words":[["G1161","And",0,3],["G5124","this",4,8],["G3004","I say",9,14],["G1242","that the covenant",16,33],["G4300","that was confirmed before",35,60],["G5259","of",61,63],["G2316","God",64,67],["G1519","in",68,70],["G5547","Christ",71,77],["G3551","the law",79,86],["G1096","which was",88,97],["G5071","four hundred",98,110],["G2532","and",111,114],["G5144","thirty",115,121],["G2094","years",122,127],["G3326","after",128,133],["G3756","cannot",135,141],["G0208","disannul",142,150],["G1519","that",152,156],["G2673","it should make",157,171],["G1860","the promise",172,183],["G2673","of none effect",184,198]]},"3:18":{"text":"For if the inheritance be of the law, it is no more of promise: but God gave it to Abraham by promise.","words":[["G1063","For",0,3],["G1487","if",4,6],["G2817","the inheritance",7,22],["G1537","be of",23,28],["G3551","the law",29,36],["G3765","it is no more",38,51],["G1537","of",52,54],["G1860","promise",55,62],["G1161","but",64,67],["G2316","God",68,71],["G5483","gave",72,76],["G0011","it to Abraham",77,90],["G1223","by",91,93],["G1860","promise",94,101]]},"3:19":{"text":"Wherefore then serveth the law? It was added because of transgressions, till the seed should come to whom the promise was made; and it was ordained by angels in the hand of a mediator.","words":[["G5101","Wherefore",0,9],["G3767","then",10,14],["G3551","serveth the law",15,30],["G4369","It was added",32,44],["G5484","because of",45,55],["G3847","transgressions",56,70],["G0891","till",72,76],["G3739","till",72,76],["G4690","the seed",77,85],["G2064","should come",86,97],["G3739","to whom",98,105],["G1861","the promise was made",106,126],["G1299","and it was ordained",128,147],["G1223","by",148,150],["G0032","angels",151,157],["G1722","in",158,160],["G5495","the hand",161,169],["G3316","of a mediator",170,183]]},"3:20":{"text":"Now a mediator is not a mediator of one, but God is one.","words":[["G1161","Now",0,3],["G3316","a mediator",4,14],["G2076","is",15,17],["G3756","not",18,21],["G1520","a mediator of one",22,39],["G1161","but",41,44],["G2316","God",45,48],["G2076","is",49,51],["G1520","one",52,55]]},"3:21":{"text":"Is the law then against the promises of God? God forbid: for if there had been a law given which could have given life, verily righteousness should have been by the law.","words":[["G3551","Is the law",0,10],["G3767","then",11,15],["G2596","against",16,23],["G1860","the promises",24,36],["G2316","of God",37,43],["G3361","God forbid",45,55],["G1096","God forbid",45,55],["G1063","for",57,60],["G1487","if",61,63],["G1325","there had been",64,78],["G3551","a law",79,84],["G1325","given",85,90],["G3588","which",91,96],["G1410","could",97,102],["G2227","have given life",103,118],["G3689","verily",120,126],["G1343","righteousness",127,140],["G0302","should",141,147],["G2258","have been",148,157],["G1537","by",158,160],["G3551","the law",161,168]]},"3:22":{"text":"But the scripture hath concluded all under sin, that the promise by faith of Jesus Christ might be given to them that believe.","words":[["G0235","But",0,3],["G1124","the scripture",4,17],["G4788","hath concluded",18,32],["G3956","all",33,36],["G5259","under",37,42],["G0266","sin",43,46],["G2443","that",48,52],["G1860","the promise",53,64],["G1537","by",65,67],["G4102","faith",68,73],["G2424","of Jesus",74,82],["G5547","Christ",83,89],["G1325","might be given",90,104],["G4100","to them that believe",105,125]]},"3:23":{"text":"But before faith came, we were kept under the law, shut up unto the faith which should afterwards be revealed.","words":[["G1161","But",0,3],["G4253","before",4,10],["G4102","faith",11,16],["G2064","came",17,21],["G5432","we were kept",23,35],["G5259","under",36,41],["G3551","the law",42,49],["G4788","shut up",51,58],["G1519","unto",59,63],["G4102","the faith",64,73],["G3195","which should afterwards",74,97],["G0601","be revealed",98,109]]},"3:24":{"text":"Wherefore the law was our schoolmaster to bring us unto Christ, that we might be justified by faith.","words":[["G5620","Wherefore",0,9],["G3551","the law",10,17],["G1096","was",18,21],["G2257","our",22,25],["G3807","schoolmaster",26,38],["G1519","to bring us unto",39,55],["G5547","Christ",56,62],["G2443","that",64,68],["G1344","we might be justified",69,90],["G1537","by",91,93],["G4102","faith",94,99]]},"3:25":{"text":"But after that faith is come, we are no longer under a schoolmaster.","words":[["G1161","But",0,3],["G4102","after that faith",4,20],["G2064","is come",21,28],["G2070","we are",30,36],["G2089","no longer",37,46],["G3765","no longer",37,46],["G5259","under",47,52],["G3807","a schoolmaster",53,67]]},"3:26":{"text":"For ye are all the children of God by faith in Christ Jesus.","words":[["G1063","For",0,3],["G2075","ye are",4,10],["G3956","all",11,14],["G5207","the children",15,27],["G2316","of God",28,34],["G1223","by",35,37],["G4102","faith",38,43],["G1722","in",44,46],["G5547","Christ",47,53],["G2424","Jesus",54,59]]},"3:27":{"text":"For as many of you as have been baptized into Christ have put on Christ.","words":[["G1063","For",0,3],["G3745","as many of you as",4,21],["G0907","have been baptized",22,40],["G1519","into",41,45],["G5547","Christ",46,52],["G1746","have put on",53,64],["G5547","Christ",65,71]]},"3:28":{"text":"There is neither Jew nor Greek, there is neither bond nor free, there is neither male nor female: for ye are all one in Christ Jesus.","words":[["G1762","There is",0,8],["G3756","neither",9,16],["G2453","Jew",17,20],["G3761","nor",21,24],["G1672","Greek",25,30],["G1762","there is",32,40],["G3756","neither",41,48],["G1401","bond",49,53],["G3761","nor",54,57],["G1658","free",58,62],["G1762","there is",64,72],["G3756","neither",73,80],["G0730","male",81,85],["G2532","nor",86,89],["G2338","female",90,96],["G1063","for",98,101],["G5210","ye",102,104],["G2075","are",105,108],["G3956","all",109,112],["G1520","one",113,116],["G1722","in",117,119],["G5547","Christ",120,126],["G2424","Jesus",127,132]]},"3:29":{"text":"And if ye be Christ's, then are ye Abraham's seed, and heirs according to the promise.","words":[["G1161","And",0,3],["G1487","if",4,6],["G5210","ye",7,9],["G5547","be Christ's",10,21],["G0686","then",23,27],["G2075","are ye",28,34],["G0011","Abraham's",35,44],["G4690","seed",45,49],["G2532","and",51,54],["G2818","heirs",55,60],["G2596","according",61,70],["G1860","to the promise",71,85]]},"4:1":{"text":"Now I say, That the heir, as long as he is a child, differeth nothing from a servant, though he be lord of all;","words":[["G1161","Now",0,3],["G3004","I say",4,9],["G2818","That the heir",11,24],["G1909","as long as",26,36],["G3745","as long as",26,36],["G5550","as long as",26,36],["G2076","he is",37,42],["G3516","a child",43,50],["G1308","differeth",52,61],["G3762","nothing",62,69],["G1401","from a servant",70,84],["G5607","though he be",86,98],["G2962","lord",99,103],["G3956","of all",104,110]]},"4:2":{"text":"But is under tutors and governors until the time appointed of the father.","words":[["G0235","But",0,3],["G2076","is",4,6],["G5259","under",7,12],["G2012","tutors",13,19],["G2532","and",20,23],["G3623","governors",24,33],["G0891","until",34,39],["G4287","the time appointed",40,58],["G3962","of the father",59,72]]},"4:3":{"text":"Even so we, when we were children, were in bondage under the elements of the world:","words":[["G2532","Even",0,4],["G3779","so",5,7],["G2249","we",8,10],["G3753","when",12,16],["G2258","we were",17,24],["G3516","children",25,33],["G2258","were",35,39],["G1402","in bondage",40,50],["G5259","under",51,56],["G4747","the elements",57,69],["G2889","of the world",70,82]]},"4:4":{"text":"But when the fulness of the time was come, God sent forth his Son, made of a woman, made under the law,","words":[["G1161","But",0,3],["G3753","when",4,8],["G4138","the fulness",9,20],["G5550","of the time",21,32],["G2064","was come",33,41],["G2316","God",43,46],["G1821","sent forth",47,57],["G0846","his",58,61],["G5207","Son",62,65],["G1096","made",67,71],["G1537","of",72,74],["G1135","a woman",75,82],["G1096","made",84,88],["G5259","under",89,94],["G3551","the law",95,102]]},"4:5":{"text":"To redeem them that were under the law, that we might receive the adoption of sons.","words":[["G2443","To",0,2],["G1805","redeem",3,9],["G5259","them that were under",10,30],["G3551","the law",31,38],["G2443","that",40,44],["G0618","we might receive",45,61],["G5206","the adoption of sons",62,82]]},"4:6":{"text":"And because ye are sons, God hath sent forth the Spirit of his Son into your hearts, crying, Abba, Father.","words":[["G1161","And",0,3],["G3754","because",4,11],["G2075","ye are",12,18],["G5207","sons",19,23],["G2316","God",25,28],["G1821","hath sent forth",29,44],["G4151","the Spirit",45,55],["G0846","of his",56,62],["G5207","Son",63,66],["G1519","into",67,71],["G5216","your",72,76],["G2588","hearts",77,83],["G2896","crying",85,91],["G0005","Abba",93,97],["G3962","Father",99,105]]},"4:7":{"text":"Wherefore thou art no more a servant, but a son; and if a son, then an heir of God through Christ.","words":[["G5620","Wherefore",0,9],["G1488","thou art",10,18],["G3765","no more",19,26],["G1401","a servant",27,36],["G0235","but",38,41],["G5207","a son",42,47],["G1161","and",49,52],["G1487","if",53,55],["G5207","a son",56,61],["G2532","then",63,67],["G2818","an heir",68,75],["G2316","of God",76,82],["G1223","through",83,90],["G5547","Christ",91,97]]},"4:8":{"text":"Howbeit then, when ye knew not God, ye did service unto them which by nature are no gods.","words":[["G0235","Howbeit",0,7],["G5119","then",8,12],["G3303","then",8,12],["G1492","when ye knew",14,26],["G3756","not",27,30],["G2316","God",31,34],["G1398","ye did service",36,50],["G5449","unto them which by nature",51,76],["G5607","are",77,80],["G3361","no",81,83],["G2316","gods",84,88]]},"4:9":{"text":"But now, after that ye have known God, or rather are known of God, how turn ye again to the weak and beggarly elements, whereunto ye desire again to be in bondage?","words":[["G1161","But",0,3],["G3568","now",4,7],["G1097","after that ye have known",9,33],["G2316","God",34,37],["G1161","or",39,41],["G3123","rather",42,48],["G1097","are known",49,58],["G5259","of",59,61],["G2316","God",62,65],["G4459","how",67,70],["G1994","turn ye",71,78],["G3825","again",79,84],["G1909","to",85,87],["G0772","the weak",88,96],["G2532","and",97,100],["G4434","beggarly",101,109],["G4747","elements",110,118],["G3739","whereunto",120,129],["G2309","ye desire",130,139],["G3825","again",140,145],["G0509","again",140,145],["G1398","to be in bondage",146,162]]},"4:10":{"text":"Ye observe days, and months, and times, and years.","words":[["G3906","Ye observe",0,10],["G2250","days",11,15],["G2532","and",17,20],["G3376","months",21,27],["G2532","and",29,32],["G2540","times",33,38],["G2532","and",40,43],["G1763","years",44,49]]},"4:11":{"text":"I am afraid of you, lest I have bestowed upon you labour in vain.","words":[["G5399","I am afraid",0,11],["G5209","of you",12,18],["G3381","lest",20,24],["G4458","lest",20,24],["G2872","I have bestowed",25,40],["G1519","upon",41,45],["G5209","you",46,49],["G2872","labour",50,56],["G1500","in vain",57,64]]},"4:12":{"text":"Brethren, I beseech you, be as I am; for I am as ye are: ye have not injured me at all.","words":[["G0080","Brethren",0,8],["G1189","I beseech",10,19],["G5216","you",20,23],["G1096","be",25,27],["G5613","as",28,30],["G1473","I",31,32],["G3754","am; for",33,40],["G2504","I",41,42],["G5613","am as",43,48],["G5210","ye",49,51],["G0091","are: ye have not injured",52,76],["G3165","me",77,79],["G3762","at all",80,86]]},"4:13":{"text":"Ye know how through infirmity of the flesh I preached the gospel unto you at the first.","words":[["G1161","",-1,-1],["G1492","Ye know",0,7],["G3754","how",8,11],["G1223","through",12,19],["G0769","infirmity",20,29],["G4561","of the flesh",30,42],["G2097","I preached the gospel",43,64],["G5213","unto you",65,73],["G4386","at the first",74,86]]},"4:14":{"text":"And my temptation which was in my flesh ye despised not, nor rejected; but received me as an angel of God, even as Christ Jesus.","words":[["G2532","And",0,3],["G3450","my",4,6],["G3986","temptation",7,17],["G1722","which was in",18,30],["G3450","my",31,33],["G4561","flesh",34,39],["G1848","ye despised",40,51],["G3756","not",52,55],["G3761","nor",57,60],["G1609","rejected",61,69],["G0235","but",71,74],["G1209","received",75,83],["G3165","me",84,86],["G5613","as",87,89],["G0032","an angel",90,98],["G2316","of God",99,105],["G5613","even as",107,114],["G5547","Christ",115,121],["G2424","Jesus",122,127]]},"4:15":{"text":"Where is then the blessedness ye spake of? for I bear you record, that, if it had been possible, ye would have plucked out your own eyes, and have given them to me.","words":[["G5101","Where",0,5],["G2258","is",6,8],["G3767","then",9,13],["G3108","the blessedness",14,29],["G5216","ye",30,32],["G1063","spake of? for",33,46],["G3140","I bear",47,53],["G5213","you",54,57],["G3140","record",58,64],["G3754","that",66,70],["G1487","if",72,74],["G1415","it had been possible",75,95],["G1846","ye would have plucked out",97,122],["G5216","your",123,127],["G3788","own eyes",128,136],["G0302","and have given them",138,157],["G1325","and have given them",138,157],["G3427","to me",158,163]]},"4:16":{"text":"Am I therefore become your enemy, because I tell you the truth?","words":[["G1096","Am I",0,4],["G5620","therefore",5,14],["G1096","become",15,21],["G5216","your",22,26],["G2190","enemy",27,32],["G0226","because I tell",34,48],["G5213","you",49,52],["G0226","the truth",53,62]]},"4:17":{"text":"They zealously affect you, but not well; yea, they would exclude you, that ye might affect them.","words":[["G2206","They zealously affect",0,21],["G5209","you",22,25],["G3756","but not",27,34],["G2573","well",35,39],["G0235","yea",41,44],["G2309","they would",46,56],["G1576","exclude",57,64],["G5209","you",65,68],["G2443","that",70,74],["G2206","ye might affect",75,90],["G0846","them",91,95]]},"4:18":{"text":"But it is good to be zealously affected always in a good thing, and not only when I am present with you.","words":[["G1161","But",0,3],["G2570","it is good",4,14],["G2206","to be zealously affected",15,39],["G3842","always",40,46],["G1722","in",47,49],["G2570","a good",50,56],["G2532","thing, and",57,67],["G3361","not",68,71],["G3440","only",72,76],["G1722","when",77,81],["G3165","I",82,83],["G3918","am present",84,94],["G4314","with",95,99],["G5209","you",100,103]]},"4:19":{"text":"My little children, of whom I travail in birth again until Christ be formed in you,","words":[["G3450","My",0,2],["G5040","little children",3,18],["G3739","of whom",20,27],["G5605","I travail in birth",28,46],["G3825","again",47,52],["G0891","until",53,58],["G3739","until",53,58],["G5547","Christ",59,65],["G3445","be formed",66,75],["G1722","in",76,78],["G5213","you",79,82]]},"4:20":{"text":"I desire to be present with you now, and to change my voice; for I stand in doubt of you.","words":[["G1161","",-1,-1],["G2309","I desire",0,8],["G3918","to be present",9,22],["G4314","with",23,27],["G5209","you",28,31],["G0737","now",32,35],["G2532","and",37,40],["G0236","to change",41,50],["G3450","my",51,53],["G5456","voice",54,59],["G3754","for",61,64],["G0639","I stand in doubt",65,81],["G1722","of",82,84],["G5213","you",85,88]]},"4:21":{"text":"Tell me, ye that desire to be under the law, do ye not hear the law?","words":[["G3004","Tell",0,4],["G3427","me",5,7],["G2309","ye that desire",9,23],["G1511","to be",24,29],["G5259","under",30,35],["G3551","the law",36,43],["G0191","do ye",45,50],["G3756","not",51,54],["G0191","hear",55,59],["G3551","the law",60,67]]},"4:22":{"text":"For it is written, that Abraham had two sons, the one by a bondmaid, the other by a freewoman.","words":[["G1063","For",0,3],["G1125","it is written",4,17],["G3754","that",19,23],["G0011","Abraham",24,31],["G2192","had",32,35],["G1417","two",36,39],["G5207","sons",40,44],["G1520","the one",46,53],["G1537","by",54,56],["G3814","a bondmaid",57,67],["G2532","",-1,-1],["G1520","the other",69,78],["G1537","by",79,81],["G1658","a freewoman",82,93]]},"4:23":{"text":"But he who was of the bondwoman was born after the flesh; but he of the freewoman was by promise.","words":[["G0235","But",0,3],["G3303","he",4,6],["G1537","who was of",7,17],["G3814","the bondwoman",18,31],["G1080","was born",32,40],["G2596","after",41,46],["G4561","the flesh",47,56],["G1161","but",58,61],["G1537","he of",62,67],["G1658","the freewoman",68,81],["G1223","was by",82,88],["G1860","promise",89,96]]},"4:24":{"text":"Which things are an allegory: for these are the two covenants; the one from the mount Sinai, which gendereth to bondage, which is Agar.","words":[["G3748","Which things",0,12],["G2076","are",13,16],["G0238","an allegory",17,28],["G1063","for",30,33],["G3778","these",34,39],["G1526","are",40,43],["G1417","the two",44,51],["G1242","covenants",52,61],["G3391","the one",63,70],["G3303","the one",63,70],["G0575","from",71,75],["G3735","the mount",76,85],["G4614","Sinai",86,91],["G1080","which gendereth",93,108],["G1519","to",109,111],["G1397","bondage",112,119],["G3748","which",121,126],["G2076","is",127,129],["G0028","Agar",130,134]]},"4:25":{"text":"For this Agar is mount Sinai in Arabia, and answereth to Jerusalem which now is, and is in bondage with her children.","words":[["G1063","For",0,3],["G0028","this Agar",4,13],["G2076","is",14,16],["G3735","mount",17,22],["G4614","Sinai",23,28],["G1722","in",29,31],["G0688","Arabia",32,38],["G1161","and",40,43],["G4960","answereth",44,53],["G2419","to Jerusalem",54,66],["G3588","which",67,72],["G3568","now is",73,79],["G1161","and",81,84],["G1398","is in bondage",85,98],["G3326","with",99,103],["G0846","her",104,107],["G5043","children",108,116]]},"4:26":{"text":"But Jerusalem which is above is free, which is the mother of us all.","words":[["G1161","But",0,3],["G2419","Jerusalem",4,13],["G0507","which is above",14,28],["G2076","is",29,31],["G1658","free",32,36],["G3748","which",38,43],["G2076","is",44,46],["G3384","the mother",47,57],["G2257","of us",58,63],["G3956","all",64,67]]},"4:27":{"text":"For it is written, Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not: for the desolate hath many more children than she which hath an husband.","words":[["G1063","For",0,3],["G1125","it is written",4,17],["G2165","Rejoice",19,26],["G4723","thou barren",28,39],["G5088","that bearest",40,52],["G3756","not",53,56],["G4486","break forth",58,69],["G2532","and",70,73],["G0994","cry",74,77],["G5605","thou that travailest",79,99],["G3756","not",100,103],["G3754","for",105,108],["G2048","the desolate",109,121],["G4183","hath many more",122,136],["G5043","children",137,145],["G3123","than",146,150],["G2228","than",146,150],["G2192","she which hath",151,165],["G0435","an husband",166,176]]},"4:28":{"text":"Now we, brethren, as Isaac was, are the children of promise.","words":[["G1161","Now",0,3],["G2249","we",4,6],["G0080","brethren",8,16],["G2596","as",18,20],["G2464","Isaac",21,26],["G2596","was",27,30],["G2070","are",32,35],["G5043","the children",36,48],["G1860","of promise",49,59]]},"4:29":{"text":"But as then he that was born after the flesh persecuted him that was born after the Spirit, even so it is now.","words":[["G0235","But",0,3],["G5618","as",4,6],["G5119","then",7,11],["G1080","he that was born",12,28],["G2596","after",29,34],["G4561","the flesh",35,44],["G1377","persecuted",45,55],["G2596","him that was born after",56,79],["G4151","the Spirit",80,90],["G2532","even",92,96],["G3779","so",97,99],["G3568","it is now",100,109]]},"4:30":{"text":"Nevertheless what saith the scripture? Cast out the bondwoman and her son: for the son of the bondwoman shall not be heir with the son of the freewoman.","words":[["G0235","Nevertheless",0,12],["G5101","what",13,17],["G3004","saith",18,23],["G1124","the scripture",24,37],["G1544","Cast out",39,47],["G3814","the bondwoman",48,61],["G2532","and",62,65],["G0846","her",66,69],["G5207","son",70,73],["G1063","for",75,78],["G5207","the son",79,86],["G3814","of the bondwoman",87,103],["G2816","shall",104,109],["G3364","not",110,113],["G2816","be heir",114,121],["G3326","with",122,126],["G5207","the son",127,134],["G1658","of the freewoman",135,151]]},"4:31":{"text":"So then, brethren, we are not children of the bondwoman, but of the free.","words":[["G0686","So then",0,7],["G0080","brethren",9,17],["G2070","we are",19,25],["G3756","not",26,29],["G5043","children",30,38],["G3814","of the bondwoman",39,55],["G0235","but",57,60],["G1658","of the free",61,72]]},"5:1":{"text":"Stand fast therefore in the liberty wherewith Christ hath made us free, and be not entangled again with the yoke of bondage.","words":[["G4739","Stand fast",0,10],["G3767","therefore",11,20],["G1657","in the liberty",21,35],["G3739","wherewith",36,45],["G5547","Christ",46,52],["G1659","hath made",53,62],["G2248","us",63,65],["G1659","free",66,70],["G2532","and",72,75],["G1758","be",76,78],["G3361","not",79,82],["G1758","entangled",83,92],["G3825","again",93,98],["G2218","with the yoke",99,112],["G1397","of bondage",113,123]]},"5:2":{"text":"Behold, I Paul say unto you, that if ye be circumcised, Christ shall profit you nothing.","words":[["G2396","Behold",0,6],["G1473","I",8,9],["G3972","Paul",10,14],["G3004","say",15,18],["G5213","unto you",19,27],["G3754","that",29,33],["G1437","if",34,36],["G4059","ye be circumcised",37,54],["G5547","Christ",56,62],["G5623","shall profit",63,75],["G5209","you",76,79],["G3762","nothing",80,87]]},"5:3":{"text":"For I testify again to every man that is circumcised, that he is a debtor to do the whole law.","words":[["G1161","For",0,3],["G3143","I testify",4,13],["G3825","again",14,19],["G3956","to every",20,28],["G0444","man",29,32],["G4059","that is circumcised",33,52],["G3754","that",54,58],["G2076","he is",59,64],["G3781","a debtor",65,73],["G4160","to do",74,79],["G3650","the whole",80,89],["G3551","law",90,93]]},"5:4":{"text":"Christ is become of no effect unto you, whosoever of you are justified by the law; ye are fallen from grace.","words":[["G5547","Christ",0,6],["G0575","is become of no effect unto you",7,38],["G2673","is become of no effect unto you",7,38],["G3748","whosoever of you",40,56],["G1344","are justified",57,70],["G1722","by",71,73],["G3551","the law",74,81],["G1601","ye are fallen from",83,101],["G5485","grace",102,107]]},"5:5":{"text":"For we through the Spirit wait for the hope of righteousness by faith.","words":[["G1063","For",0,3],["G2249","we",4,6],["G4151","through the Spirit",7,25],["G0553","wait for",26,34],["G1680","the hope",35,43],["G1343","of righteousness",44,60],["G1537","by",61,63],["G4102","faith",64,69]]},"5:6":{"text":"For in Jesus Christ neither circumcision availeth any thing, nor uncircumcision; but faith which worketh by love.","words":[["G1063","For",0,3],["G1722","in",4,6],["G2424","Jesus",7,12],["G5547","Christ",13,19],["G3777","neither",20,27],["G4061","circumcision",28,40],["G2480","availeth",41,49],["G5100","any thing",50,59],["G3777","nor",61,64],["G0203","uncircumcision",65,79],["G0235","but",81,84],["G4102","faith",85,90],["G1754","which worketh",91,104],["G1223","by",105,107],["G0026","love",108,112]]},"5:7":{"text":"Ye did run well; who did hinder you that ye should not obey the truth?","words":[["G5143","Ye did run",0,10],["G2573","well",11,15],["G5101","who",17,20],["G0348","did hinder",21,31],["G1465","did hinder",21,31],["G5209","you",32,35],["G3982","that ye should",36,50],["G3361","not",51,54],["G3982","obey",55,59],["G0225","the truth",60,69]]},"5:8":{"text":"This persuasion cometh not of him that calleth you.","words":[["G3988","This persuasion",0,15],["G3756","cometh not",16,26],["G1537","of",27,29],["G2564","him that calleth",30,46],["G5209","you",47,50]]},"5:9":{"text":"A little leaven leaveneth the whole lump.","words":[["G3398","A little",0,8],["G2219","leaven",9,15],["G2220","leaveneth",16,25],["G3650","the whole",26,35],["G5445","lump",36,40]]},"5:10":{"text":"I have confidence in you through the Lord, that ye will be none otherwise minded: but he that troubleth you shall bear his judgment, whosoever he be.","words":[["G1473","I",0,1],["G3982","have confidence",2,17],["G1519","in",18,20],["G5209","you",21,24],["G1722","through",25,32],["G2962","the Lord",33,41],["G3754","that",43,47],["G5426","ye will be",48,58],["G3762","none",59,63],["G0243","otherwise",64,73],["G5426","minded",74,80],["G1161","but",82,85],["G5015","he that troubleth",86,103],["G5209","you",104,107],["G0941","shall bear",108,118],["G2917","his judgment",119,131],["G3748","whosoever",133,142],["G0302","he be",143,148],["G5600","he be",143,148]]},"5:11":{"text":"And I, brethren, if I yet preach circumcision, why do I yet suffer persecution? then is the offence of the cross ceased.","words":[["G1161","And",0,3],["G1473","I",4,5],["G0080","brethren",7,15],["G1487","if",17,19],["G2784","I",20,21],["G2089","yet",22,25],["G2784","preach",26,32],["G4061","circumcision",33,45],["G5101","why",47,50],["G1377","do I",51,55],["G2089","yet",56,59],["G1377","suffer persecution",60,78],["G0686","then",80,84],["G2673","is",85,87],["G4625","the offence",88,99],["G4716","of the cross",100,112],["G2673","ceased",113,119]]},"5:12":{"text":"I would they were even cut off which trouble you.","words":[["G3785","I would",0,7],["G0609","they were",8,17],["G2532","even",18,22],["G0609","cut off",23,30],["G0387","which trouble",31,44],["G5209","you",45,48]]},"5:13":{"text":"For, brethren, ye have been called unto liberty; only use not liberty for an occasion to the flesh, but by love serve one another.","words":[["G1063","For",0,3],["G0080","brethren",5,13],["G5210","ye",15,17],["G2564","have been called",18,34],["G1909","unto",35,39],["G1657","liberty",40,47],["G3440","only",49,53],["G3361","use not",54,61],["G1657","liberty",62,69],["G1519","for",70,73],["G0874","an occasion",74,85],["G4561","to the flesh",86,98],["G0235","but",100,103],["G1223","by",104,106],["G0026","love",107,111],["G1398","serve",112,117],["G0240","one another",118,129]]},"5:14":{"text":"For all the law is fulfilled in one word, even in this; Thou shalt love thy neighbour as thyself.","words":[["G1063","For",0,3],["G3956","all",4,7],["G3551","the law",8,15],["G4137","is fulfilled",16,28],["G1722","in",29,31],["G1520","one",32,35],["G3056","word",36,40],["G1722","even in",42,49],["G0025","this; Thou shalt love",50,71],["G4675","thy",72,75],["G4139","neighbour",76,85],["G5613","as",86,88],["G1438","thyself",89,96]]},"5:15":{"text":"But if ye bite and devour one another, take heed that ye be not consumed one of another.","words":[["G1161","But",0,3],["G1487","if",4,6],["G1143","ye bite",7,14],["G2532","and",15,18],["G2719","devour",19,25],["G0240","one another",26,37],["G0991","take heed",39,48],["G0335","that ye be",49,59],["G3361","not",60,63],["G0355","consumed",64,72],["G0240","one",73,76],["G5259","of",77,79],["G0240","another",80,87]]},"5:16":{"text":"This I say then, Walk in the Spirit, and ye shall not fulfil the lust of the flesh.","words":[["G3004","This I say",0,10],["G1161","then",11,15],["G4043","Walk",17,21],["G4151","in the Spirit",22,35],["G2532","and",37,40],["G5055","ye shall",41,49],["G3364","not",50,53],["G5055","fulfil",54,60],["G1939","the lust",61,69],["G4561","of the flesh",70,82]]},"5:17":{"text":"For the flesh lusteth against the Spirit, and the Spirit against the flesh: and these are contrary the one to the other: so that ye cannot do the things that ye would.","words":[["G1063","For",0,3],["G4561","the flesh",4,13],["G1937","lusteth",14,21],["G2596","against",22,29],["G4151","the Spirit",30,40],["G1161","and",42,45],["G4151","the Spirit",46,56],["G2596","against",57,64],["G4561","the flesh",65,74],["G1161","and",76,79],["G5023","these",80,85],["G0480","are contrary",86,98],["G0240","the one to the other",99,119],["G2443","so that",121,128],["G3363","ye cannot",129,138],["G4160","do",139,141],["G5023","the things",142,152],["G3739","that",153,157],["G0302","that",153,157],["G2309","ye would",158,166]]},"5:18":{"text":"But if ye be led of the Spirit, ye are not under the law.","words":[["G1161","But",0,3],["G1487","if",4,6],["G0071","ye be led",7,16],["G4151","of the Spirit",17,30],["G2075","ye are",32,38],["G3756","not",39,42],["G5259","under",43,48],["G3551","the law",49,56]]},"5:19":{"text":"Now the works of the flesh are manifest, which are these; Adultery, fornication, uncleanness, lasciviousness,","words":[["G1161","Now",0,3],["G2041","the works",4,13],["G4561","of the flesh",14,26],["G2076","are",27,30],["G5318","manifest",31,39],["G3748","which",41,46],["G2076","are",47,50],["G3430","these; Adultery",51,66],["G4202","fornication",68,79],["G0167","uncleanness",81,92],["G0766","lasciviousness",94,108]]},"5:20":{"text":"Idolatry, witchcraft, hatred, variance, emulations, wrath, strife, seditions, heresies,","words":[["G1495","Idolatry",0,8],["G5331","witchcraft",10,20],["G2189","hatred",22,28],["G2054","variance",30,38],["G2205","emulations",40,50],["G2372","wrath",52,57],["G2052","strife",59,65],["G1370","seditions",67,76],["G0139","heresies",78,86]]},"5:21":{"text":"Envyings, murders, drunkenness, revellings, and such like: of the which I tell you before, as I have also told you in time past, that they which do such things shall not inherit the kingdom of God.","words":[["G5355","Envyings",0,8],["G5408","murders",10,17],["G3178","drunkenness",19,30],["G2970","revellings",32,42],["G2532","and",44,47],["G5125","such",48,52],["G3664","like",53,57],["G3739","of the which",59,71],["G4302","I tell",72,78],["G5213","you",79,82],["G4302","before",83,89],["G2531","as",91,93],["G4277","I have",94,100],["G2532","also",101,105],["G4277","told you in time past",106,127],["G3754","that",129,133],["G4238","they which do",134,147],["G5108","such things",148,159],["G2816","shall",160,165],["G3756","not",166,169],["G2816","inherit",170,177],["G0932","the kingdom",178,189],["G2316","of God",190,196]]},"5:22":{"text":"But the fruit of the Spirit is love, joy, peace, longsuffering, gentleness, goodness, faith,","words":[["G1161","But",0,3],["G2590","the fruit",4,13],["G4151","of the Spirit",14,27],["G2076","is",28,30],["G0026","love",31,35],["G5479","joy",37,40],["G1515","peace",42,47],["G3115","longsuffering",49,62],["G5544","gentleness",64,74],["G0019","goodness",76,84],["G4102","faith",86,91]]},"5:23":{"text":"Meekness, temperance: against such there is no law.","words":[["G4236","Meekness",0,8],["G1466","temperance",10,20],["G2596","against",22,29],["G5108","such",30,34],["G2076","there is",35,43],["G3756","no",44,46],["G3551","law",47,50]]},"5:24":{"text":"And they that are Christ's have crucified the flesh with the affections and lusts.","words":[["G1161","And",0,3],["G3588","they that are",4,17],["G5547","Christ's",18,26],["G4717","have crucified",27,41],["G4561","the flesh",42,51],["G4862","with",52,56],["G3804","the affections",57,71],["G2532","and",72,75],["G1939","lusts",76,81]]},"5:25":{"text":"If we live in the Spirit, let us also walk in the Spirit.","words":[["G1487","If",0,2],["G2198","we live",3,10],["G4151","in the Spirit",11,24],["G4748","let us",26,32],["G2532","also",33,37],["G4748","walk",38,42],["G4151","in the Spirit",43,56]]},"5:26":{"text":"Let us not be desirous of vain glory, provoking one another, envying one another.","words":[["G1096","Let us",0,6],["G3361","not",7,10],["G1096","be",11,13],["G2755","desirous of vain glory",14,36],["G4292","provoking",38,47],["G0240","one another",48,59],["G5354","envying",61,68],["G0240","one another",69,80]]},"6:1":{"text":"Brethren, if a man be overtaken in a fault, ye which are spiritual, restore such an one in the spirit of meekness; considering thyself, lest thou also be tempted.","words":[["G0080","Brethren",0,8],["G1437","if",10,12],["G2532","if",10,12],["G0444","a man",13,18],["G4301","be overtaken",19,31],["G1722","in",32,34],["G5100","a",35,36],["G3900","fault",37,42],["G5210","ye",44,46],["G3588","which",47,52],["G4152","are spiritual",53,66],["G2675","restore",68,75],["G5108","such an one",76,87],["G1722","in",88,90],["G4151","the spirit",91,101],["G4236","of meekness",102,113],["G4648","considering",115,126],["G4572","thyself",127,134],["G3361","lest",136,140],["G4771","thou",141,145],["G2532","also",146,150],["G3985","be tempted",151,161]]},"6:2":{"text":"Bear ye one another's burdens, and so fulfil the law of Christ.","words":[["G0941","Bear ye",0,7],["G0240","one another's",8,21],["G0922","burdens",22,29],["G2532","and",31,34],["G3779","so",35,37],["G0378","fulfil",38,44],["G3551","the law",45,52],["G5547","of Christ",53,62]]},"6:3":{"text":"For if a man think himself to be something, when he is nothing, he deceiveth himself.","words":[["G1063","For",0,3],["G1536","if a man",4,12],["G1380","think himself",13,26],["G1511","to be",27,32],["G5100","something",33,42],["G5607","when he is",44,54],["G3367","nothing",55,62],["G5422","he deceiveth",64,76],["G1438","himself",77,84]]},"6:4":{"text":"But let every man prove his own work, and then shall he have rejoicing in himself alone, and not in another.","words":[["G1161","But",0,3],["G1381","let",4,7],["G1538","every man",8,17],["G1381","prove",18,23],["G1438","his own",24,31],["G2041","work",32,36],["G2532","and",38,41],["G5119","then",42,46],["G2192","shall he have",47,60],["G2745","rejoicing",61,70],["G1519","in",71,73],["G1438","himself",74,81],["G3441","alone",82,87],["G2532","and",89,92],["G3756","not",93,96],["G1519","in",97,99],["G2087","another",100,107]]},"6:5":{"text":"For every man shall bear his own burden.","words":[["G1063","For",0,3],["G1538","every man",4,13],["G0941","shall bear",14,24],["G2398","his own",25,32],["G5413","burden",33,39]]},"6:6":{"text":"Let him that is taught in the word communicate unto him that teacheth in all good things.","words":[["G1161","Let",0,3],["G2727","him that is taught",4,22],["G3056","in the word",23,34],["G2841","communicate",35,46],["G2727","unto him that teacheth",47,69],["G1722","in",70,72],["G3956","all",73,76],["G0018","good things",77,88]]},"6:7":{"text":"Be not deceived; God is not mocked: for whatsoever a man soweth, that shall he also reap.","words":[["G4105","Be",0,2],["G3361","not",3,6],["G4105","deceived",7,15],["G2316","God",17,20],["G3456","is",21,23],["G3756","not",24,27],["G3456","mocked",28,34],["G1063","for",36,39],["G3739","whatsoever",40,50],["G1437","whatsoever",40,50],["G0444","a man",51,56],["G4687","soweth",57,63],["G5124","that",65,69],["G2325","shall he",70,78],["G2532","also",79,83],["G2325","reap",84,88]]},"6:8":{"text":"For he that soweth to his flesh shall of the flesh reap corruption; but he that soweth to the Spirit shall of the Spirit reap life everlasting.","words":[["G3754","For",0,3],["G4687","he that soweth",4,18],["G1519","to",19,21],["G1438","his",22,25],["G4561","flesh",26,31],["G2325","shall",32,37],["G1537","of",38,40],["G4561","the flesh",41,50],["G2325","reap",51,55],["G5356","corruption",56,66],["G1161","but",68,71],["G4687","he that soweth",72,86],["G1519","to",87,89],["G4151","the Spirit",90,100],["G2325","shall",101,106],["G1537","of",107,109],["G4151","the Spirit",110,120],["G2325","reap",121,125],["G2222","life",126,130],["G0166","everlasting",131,142]]},"6:9":{"text":"And let us not be weary in well doing: for in due season we shall reap, if we faint not.","words":[["G1161","And",0,3],["G1573","let us",4,10],["G3361","not",11,14],["G1573","be weary",15,23],["G2570","in well",24,31],["G4160","doing",32,37],["G1063","for",39,42],["G2398","in due",43,49],["G2540","season",50,56],["G2325","we shall reap",57,70],["G1590","if we faint",72,83],["G3361","not",84,87]]},"6:10":{"text":"As we have therefore opportunity, let us do good unto all men, especially unto them who are of the household of faith.","words":[["G5613","As",0,2],["G2192","we have",3,10],["G0686","therefore",11,20],["G3767","therefore",11,20],["G2540","opportunity",21,32],["G2038","let us do",34,43],["G0018","good",44,48],["G4314","unto",49,53],["G3956","all",54,57],["G1161","men, especially",58,73],["G3122","men, especially",58,73],["G4314","unto",74,78],["G3609","them who are of the household",79,108],["G4102","of faith",109,117]]},"6:11":{"text":"Ye see how large a letter I have written unto you with mine own hand.","words":[["G1492","Ye see",0,6],["G4080","how large",7,16],["G1121","a letter",17,25],["G1125","I have written",26,40],["G5213","unto you",41,49],["G1699","with mine own",50,63],["G5495","hand",64,68]]},"6:12":{"text":"As many as desire to make a fair shew in the flesh, they constrain you to be circumcised; only lest they should suffer persecution for the cross of Christ.","words":[["G3745","As many as",0,10],["G2309","desire",11,17],["G2146","to make a fair shew",18,37],["G1722","in",38,40],["G4561","the flesh",41,50],["G3778","they",52,56],["G0315","constrain",57,66],["G5209","you",67,70],["G4059","to be circumcised",71,88],["G3440","only",90,94],["G3363","lest",95,99],["G1377","they should suffer persecution",100,130],["G4716","for the cross",131,144],["G5547","of Christ",145,154]]},"6:13":{"text":"For neither they themselves who are circumcised keep the law; but desire to have you circumcised, that they may glory in your flesh.","words":[["G1063","For",0,3],["G3761","neither",4,11],["G0846","they themselves",12,27],["G4059","who are circumcised",28,47],["G5442","keep",48,52],["G3551","the law",53,60],["G0235","but",62,65],["G2309","desire",66,72],["G4059","to have",73,80],["G5209","you",81,84],["G4059","circumcised",85,96],["G2443","that",98,102],["G2744","they may glory",103,117],["G1722","in",118,120],["G5212","your",121,125],["G4561","flesh",126,131]]},"6:14":{"text":"But God forbid that I should glory, save in the cross of our Lord Jesus Christ, by whom the world is crucified unto me, and I unto the world.","words":[["G1161","But",0,3],["G3361","God forbid",4,14],["G1096","God forbid",4,14],["G1698","that I",15,21],["G2744","should glory",22,34],["G1508","save",36,40],["G1722","in",41,43],["G4716","the cross",44,53],["G2257","of our",54,60],["G2962","Lord",61,65],["G2424","Jesus",66,71],["G5547","Christ",72,78],["G1223","by",80,82],["G3739","whom",83,87],["G2889","the world",88,97],["G4717","is crucified",98,110],["G1698","unto me",111,118],["G2504","and I",120,125],["G2889","unto the world",126,140]]},"6:15":{"text":"For in Christ Jesus neither circumcision availeth any thing, nor uncircumcision, but a new creature.","words":[["G1063","For",0,3],["G1722","in",4,6],["G5547","Christ",7,13],["G2424","Jesus",14,19],["G3777","neither",20,27],["G4061","circumcision",28,40],["G2480","availeth",41,49],["G5100","any thing",50,59],["G3777","nor",61,64],["G0203","uncircumcision",65,79],["G0235","but",81,84],["G2537","a new",85,90],["G2937","creature",91,99]]},"6:16":{"text":"And as many as walk according to this rule, peace be on them, and mercy, and upon the Israel of God.","words":[["G2532","And",0,3],["G3745","as many as",4,14],["G4748","walk",15,19],["G2583","according to",20,32],["G5129","this",33,37],["G2583","rule",38,42],["G1515","peace",44,49],["G1909","be on",50,55],["G0846","them",56,60],["G2532","and",62,65],["G1656","mercy",66,71],["G2532","and",73,76],["G1909","upon",77,81],["G2474","the Israel",82,92],["G2316","of God",93,99]]},"6:17":{"text":"From henceforth let no man trouble me: for I bear in my body the marks of the Lord Jesus.","words":[["G3064","From henceforth",0,15],["G3930","let",16,19],["G3367","no man",20,26],["G3930","trouble",27,34],["G2873","me",35,37],["G3427","me",35,37],["G1063","for",39,42],["G1473","I",43,44],["G0941","bear",45,49],["G1722","in",50,52],["G3450","my",53,55],["G4983","body",56,60],["G4742","the marks",61,70],["G2962","of the Lord",71,82],["G2424","Jesus",83,88]]},"6:18":{"text":"Brethren, the grace of our Lord Jesus Christ be with your spirit. Amen.","words":[["G0080","Brethren",0,8],["G5485","the grace",10,19],["G2257","of our",20,26],["G2962","Lord",27,31],["G2424","Jesus",32,37],["G5547","Christ",38,44],["G3326","be with",45,52],["G5216","your",53,57],["G4151","spirit",58,64],["G0281","Amen",66,70]]}}};
